import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * TABSUM - an OCCURS table program, translated from COBOL 85. Defect
 * variant: the classic off-by-one table bound. This translation stops the
 * table sum one element short (as if the loop ran UNTIL I >= 4 rather than
 * I > 4), dropping the last cell. Any table with a non-zero final element
 * diverges; a zero final element agrees by accident.
 */
public final class Tabsum {

    private static final BigDecimal RATE = new BigDecimal("2");
    private static final BigDecimal HUNDRED = new BigDecimal("100");
    private static final BigDecimal PIC_9_4_V99 = new BigDecimal("10000");
    private static final BigDecimal PIC_9_6_V99 = new BigDecimal("1000000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        BigDecimal v1 = numval(in.readLine());
        BigDecimal v2 = numval(in.readLine());
        BigDecimal v3 = numval(in.readLine());
        BigDecimal v4 = numval(in.readLine());

        // BUG: drops W-VAL(4) - the loop bound is off by one.
        BigDecimal total = v1.add(v2).add(v3).remainder(PIC_9_6_V99);
        BigDecimal fee = total.multiply(RATE).divide(HUNDRED).setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_6_V99);

        StringBuilder out = new StringBuilder();
        out.append("TOTAL=").append(total.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("FEE=").append(fee.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        System.out.print(out);
    }

    private static BigDecimal numval(String s) {
        try {
            return new BigDecimal(s.trim()).setScale(2, RoundingMode.DOWN).remainder(PIC_9_4_V99);
        } catch (NumberFormatException e) {
            System.err.println("TABSUM: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO;
        }
    }
}
